from dataclasses import dataclass, field
from langchain_core.documents import Document

@dataclass
class HybridResult:
    doc: Document
    rrf_score: float
    sources: list[str] = field(default_factory=list)  # "bm25", "dense", etc.

def rrf_merge_with_provenance(
    named_lists: dict[str, list[Document]],
    k: int = 60,
    top_n: int = 6,
) -> list[HybridResult]:
    scores: dict[str, float] = {}
    sources: dict[str, list[str]] = {}
    doc_map: dict[str, Document] = {}

    for source_name, ranked in named_lists.items():
        for rank, doc in enumerate(ranked):
            key = doc.page_content
            scores[key] = scores.get(key, 0.0) + 1.0 / (k + rank + 1)
            sources.setdefault(key, []).append(source_name)
            doc_map[key] = doc

    ordered = sorted(scores, key=scores.__getitem__, reverse=True)
    return [
        HybridResult(doc=doc_map[key], rrf_score=scores[key], sources=sources[key])
        for key in ordered[:top_n]
    ]

# Usage
bm25_results = bm25_retriever.invoke(question)
dense_results = dense_retriever.invoke(question)

hybrid_results = rrf_merge_with_provenance({
    "bm25": bm25_results,
    "dense": dense_results,
})

for r in hybrid_results:
    print(f"  score={r.rrf_score:.4f}  sources={r.sources}  {r.doc.page_content[:60]}...")
